    switch(status) {
      case 'Active': return 'bg-green-100 text-green-800 border-green-200';
      case 'Excess': return 'bg-amber-100 text-amber-800 border-amber-200';
      case 'Disposed': return 'bg-slate-100 text-slate-800 border-slate-200';
