const NavItem = ({ icon: Icon, label, path, active, collapsed, isSubItem = false, onClick }: any) => {
  const navigate = useNavigate();
  return (
    <button
      onClick={() => {
        navigate(path);
        if (onClick) onClick();
      }}
      className={`w-full flex items-center gap-3 pr-2 py-3 md:py-2 transition-colors duration-200 group
