const NavItem = ({ icon: Icon, label, path, active, collapsed, isSubItem = false, onClick }: any) => {
  const navigate = useNavigate();
  return (
    <button
      onClick={() => {
        navigate(path);
        if (onClick) onClick();
      }}
      className={`w-full flex items-center gap-3 pr-2 py-3 md:py-2 transition-colors duration-200 group
        ${isSubItem ? 'pl-8' : 'pl-4'}
        ${active ? 'bg-slate-800/50 text-white shadow-sm' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}
      `}
    >
      <Icon size={20} className={`flex-shrink-0 ${active ? 'text-blue-400' : ''}`} />
      {!collapsed && <span className="font-medium text-sm flex-1 text-left">{label}</span>}
    </button>
  );
};

const NavGroup = ({ icon: Icon, label, children, collapsed, paths }: any) => {
  const location = useLocation();
  const isActive = paths.some((path: string) => location.pathname === path || (path !== '/' && location.pathname.startsWith(path)));
  const [isOpen, setIsOpen] = useState(isActive);

  useEffect(() => {
    if (isActive) {
      setIsOpen(true);
    }
  }, [isActive]);

  return (
    <div className="border-b border-slate-800/50 last:border-b-0">
      <button
        onClick={() => setIsOpen(!isOpen)}
        className={`w-full flex items-center gap-3 pl-4 pr-2 py-3.5 md:py-3 transition-colors duration-200 ${isActive ? 'text-white' : 'text-slate-400'} hover:bg-slate-800 hover:text-white`}
      >
        <Icon size={20} className="flex-shrink-0" />
        {!collapsed && <span className="font-semibold text-sm flex-1 text-left">{label}</span>}
        {!collapsed && <ChevronDown size={16} className={`transition-transform ${isOpen ? 'rotate-180' : ''}`} />}
      </button>
      {!collapsed && isOpen && (
        <div className="py-1 bg-black/20">
          {children}
        </div>
      )}
    </div>
  );
};

